import React, { useEffect, useRef } from 'react';
import { Input, Select, useViewMobileLayout } from '@linm-soft-org/linm-web-common-components';
import { useLinesGridMessageTitles } from '../../../../../hooks/useLinesGridMessageTitles';
import { useSelectedLineRowSync } from '../../../../../hooks/useSelectedLineRowSync';
import { AccountSearchInput, LineMaterialSearchCell, MaterialLineTableHeaders, useAccountSearchAsOfDate } from '../../../../../components/search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import { formatMoneyVnd } from '../../../../../utils/formatters';
import { LocaleNumberInput } from '../../../../../components/form/LocaleNumberInput';
import { isEditingMode } from '../../../../../components/form';
import { purchaseInvoiceFormLabels } from '../../../../../constants/purchaseInvoiceFormLabels';
import { lineAmount, lineTax } from '../mappers/purchaseInvoiceMappers';
import type { usePurchaseInvoiceFormController } from '../hooks/usePurchaseInvoiceFormController';

type Vm = ReturnType<typeof usePurchaseInvoiceFormController>;

function isLineRowFieldTarget(target: HTMLElement): boolean {
  return !!target.closest(
    'input, textarea, select, button, a, [role="option"], [role="listbox"]',
  );
}

export const PurchaseInvoiceLinesSection: React.FC<{ vm: Vm }> = ({ vm }) => {
  const df = vm.styles;
  const labels = purchaseInvoiceFormLabels;
  const {
    tid,
    toolbarMode,
    isStatusLocked,
    fieldLock,
    invoiceDate,
    lines,
    fieldErrors,
    taxRateSelectOptions,
    resolveUnitName,
    updateLine,
    handleAddLine,
    handleCopyLine,
    handleSelectLine,
    selectedLineIndex,
    highlightLineIndex,
    removeLine,
  } = vm;

  const accountSearchOptions = useAccountSearchAsOfDate(invoiceDate);

  const { isReadOnly, searchDisabled, searchViewClass, viewSectionClass } = fieldLock;
  const lineAccountSearchClass = [searchViewClass, df.lineAccountSearch].filter(Boolean).join(' ');
  const canEditLines = isEditingMode(toolbarMode) && !isStatusLocked;

  const sectionRef = useRef<HTMLDivElement>(null);
  const rowRefs = useRef<(HTMLTableRowElement | null)[]>([]);

  useSelectedLineRowSync(rowRefs, selectedLineIndex, {
    sectionRef,
    isFieldTarget: isLineRowFieldTarget,
  });

  useLinesGridMessageTitles(sectionRef, [fieldErrors, lines.length]);

  useEffect(() => {
    const root = sectionRef.current;
    if (!root) return undefined;

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key !== 'ArrowUp' && e.key !== 'ArrowDown') return;
      const target = e.target as HTMLElement;
      if (isLineRowFieldTarget(target)) return;
      if (!root.contains(target)) return;

      e.preventDefault();
      if (e.key === 'ArrowDown') {
        handleSelectLine(Math.min(selectedLineIndex + 1, lines.length - 1));
      } else {
        handleSelectLine(Math.max(selectedLineIndex - 1, 0));
      }
    };

    root.addEventListener('keydown', onKeyDown);
    return () => root.removeEventListener('keydown', onKeyDown);
  }, [handleSelectLine, lines.length, selectedLineIndex]);

  const focusRow = (idx: number) => {
    rowRefs.current[idx]?.focus({ preventScroll: true });
  };

  const viewMobile = useViewMobileLayout();
  const linesTableClass = [df.linesTable, viewMobile ? df.linesTableStacked : ''].filter(Boolean).join(' ');

  return (
    <div
      ref={sectionRef}
      className={[df.section, df.linesSection, viewSectionClass].filter(Boolean).join(' ')}
      data-testid={tid('section-lines')}
    >
      <h2 className={df.sectionTitle}>{labels.sectionLines}</h2>
      <div className={df.tableWrapper}>
        <table className={linesTableClass}>
          <colgroup>
            <col className={df.linesColMatCode} />
            <col className={df.linesColMatName} />
            <col className={df.linesColUnit} />
            <col className={df.linesColQty} />
            <col className={df.linesColUnitPrice} />
            <col className={df.linesColTax} />
            <col className={df.linesColDebit} />
            <col className={df.linesColAmount} />
            {canEditLines && <col className={df.linesColDel} />}
          </colgroup>
          <thead>
            <tr>
              <MaterialLineTableHeaders />
              <th className={df.thUnit}>{labels.lineUnit}</th>
              <th className={df.thAmount}>{labels.lineQty}</th>
              <th className={df.thAmount}>{labels.lineUnitPrice}</th>
              <th>{labels.lineTax}</th>
              <th>{labels.lineDebitAccount}</th>
              <th className={df.thAmount}>{labels.lineAmount}</th>
              {canEditLines && <th className={df.thDel} />}
            </tr>
          </thead>
          <tbody>
            {lines.map((line, idx) => {
              const isSelected = selectedLineIndex === idx;
              const isHighlight = highlightLineIndex === idx;
              const rowClass = [
                df.lineRow,
                isSelected ? df.lineRowSelected : '',
                isHighlight ? df.lineRowHighlight : '',
                isHighlight ? df.lineRowEnter : '',
              ]
                .filter(Boolean)
                .join(' ');

              return (
                <tr
                  key={idx}
                  ref={el => {
                    rowRefs.current[idx] = el;
                  }}
                  className={rowClass}
                  data-testid={tid(`line-${idx + 1}`)}
                  tabIndex={isSelected ? 0 : -1}
                  aria-selected={isSelected}
                  onClick={e => {
                    handleSelectLine(idx);
                    const target = e.target as HTMLElement;
                    if (isLineRowFieldTarget(target)) return;
                    focusRow(idx);
                  }}
                >
                  <LineMaterialSearchCell
                    materialCode={line.materialCode}
                    materialName={line.materialName}
                    dataLabel={`${labels.lineMatCode} / ${labels.lineMatName}`}
                    cellId={tid(`line-${idx + 1}-material`)}
                    disabled={isReadOnly}
                    testId={tid(`line-${idx + 1}-material`)}
                    error={fieldErrors.lines?.[idx]?.materialCode}
                    onSelect={m =>
                      updateLine(idx, {
                        materialCode: m.code,
                        materialName: m.name,
                        unitCode: m.unitCode ?? line.unitCode,
                        unitName: resolveUnitName(m.unitCode ?? line.unitCode),
                        unitPrice: m.standardCost ?? line.unitPrice,
                        debitAccountCode: m.accountCode ?? line.debitAccountCode,
                      })
                    }
                    onClear={() =>
                      updateLine(idx, { materialCode: '', materialName: '', unitCode: '', unitName: '' })
                    }
                  />
                  <td data-testid={tid(`line-${idx + 1}-unitCode`)} data-label={labels.lineUnit}>
                    <Input value={line.unitName || resolveUnitName(line.unitCode)} disabled readOnly />
                  </td>
                  <td
                    id={tid(`line-${idx + 1}-quantity`)}
                    data-testid={tid(`line-${idx + 1}-quantity`)}
                    data-label={labels.lineQty}
                  >
                    <LocaleNumberInput
                      format="quantity"
                      value={line.quantity}
                      error={fieldErrors.lines?.[idx]?.quantity}
                      onChange={q => updateLine(idx, { quantity: q })}
                      disabled={isReadOnly}
                    />
                  </td>
                  <td
                    id={tid(`line-${idx + 1}-unitPrice`)}
                    data-testid={tid(`line-${idx + 1}-unitPrice`)}
                    data-label={labels.lineUnitPrice}
                  >
                    <LocaleNumberInput
                      format="money"
                      value={line.unitPrice}
                      error={fieldErrors.lines?.[idx]?.unitPrice}
                      onChange={p => updateLine(idx, { unitPrice: p })}
                      disabled={isReadOnly}
                    />
                  </td>
                  <td
                    id={tid(`line-${idx + 1}-taxRate`)}
                    data-testid={tid(`line-${idx + 1}-taxRate`)}
                    data-label={labels.lineTax}
                  >
                    <Select
                      value={String(line.taxRate)}
                      error={fieldErrors.lines?.[idx]?.taxRate}
                      onChange={e => updateLine(idx, { taxRate: Number(e.target.value) })}
                      options={taxRateSelectOptions}
                      disabled={isReadOnly}
                    />
                  </td>
                  <td
                    id={tid(`line-${idx + 1}-debitAccountCode`)}
                    data-testid={tid(`line-${idx + 1}-debitAccountCode`)}
                    data-label={labels.lineDebitAccount}
                  >
                    <AccountSearchInput
                      api={erpFinanceAccountSearchApi}
                      configOptions={accountSearchOptions}
                      value={line.debitAccountCode}
                      primaryDisplay={formatAccountDisplay(line.debitAccountCode, line.debitAccountName)}
                      onChange={a => updateLine(idx, { debitAccountCode: a.code, debitAccountName: a.name })}
                      onClear={() => updateLine(idx, { debitAccountCode: '', debitAccountName: '' })}
                      showSecondaryInput={false}
                      error={fieldErrors.lines?.[idx]?.debitAccountCode}
                      className={lineAccountSearchClass}
                      disabled={searchDisabled}
                    />
                  </td>
                  <td className={df.tdAmount} data-label={labels.lineAmount}>
                    {formatMoneyVnd(lineAmount(line) + lineTax(line))}
                  </td>
                  {canEditLines && (
                    <td className={df.tdDel}>
                      <button
                        type="button"
                        className={df.btnDeleteLine}
                        onClick={() => removeLine(idx)}
                        title="Xóa dòng"
                      >
                        ×
                      </button>
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      {canEditLines && (
        <div className={df.linesActions}>
          <button
            type="button"
            className={df.btnAddLine}
            data-testid={tid('add-line-btn')}
            onClick={handleAddLine}
          >
            {labels.addLine}
          </button>
          <button
            type="button"
            className={df.btnCopyLine}
            data-testid={tid('copy-line-btn')}
            onClick={handleCopyLine}
            disabled={lines.length === 0}
          >
            {labels.copyLine}
          </button>
        </div>
      )}
    </div>
  );
};
